; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] true

[if exp='o.オークの拠点を制圧せよ.flag == 3']
	@delevent
	[texton]
	There are traces of large numbers of orcs having lived here, but no sign of orcs at all.[k]
	Perhaps the guard captain exterminated the orcs?[k]
	[textoff]
	[eventoff]
[endif]

@delevent
@delevent name=全般 num=66
@wait time=500 cond='WAY != "e"'
@walk turn=e cond='WAY != "e"'
@wait time=500
@eval exp='o.オークの拠点を制圧せよ.flag = 2'
@jump storage="main10.scn" target=*orc_1

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger
*event_3
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("life", 300)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
